    adobe_byodStoreLocatorVisitors_programmatic,adobe_byodStoreLocatorVisitors_programmatic_wow,adobe_byodStoreLocatorVisitors_programmatic_ly,CASE WHEN adobe_byodStoreLocatorVisitors_programmatic_wow IS NULL OR adobe_byodStoreLocatorVisitors_programmatic_wow = 0 THEN NULL ELSE ROUND((adobe_byodStoreLocatorVisitors_programmatic - adobe_byodStoreLocatorVisitors_programmatic_wow) / adobe_byodStoreLocatorVisitors_programmatic_wow, 6) END AS adobe_byodStoreLocatorVisitors_programmatic_wow_pct, CASE WHEN adobe_byodStoreLocatorVisitors_programmatic_ly IS NULL OR adobe_byodStoreLocatorVisitors_programmatic_ly = 0 THEN NULL ELSE ROUND((adobe_byodStoreLocatorVisitors_programmatic - adobe_byodStoreLocatorVisitors_programmatic_ly) / adobe_byodStoreLocatorVisitors_programmatic_ly, 6) END AS adobe_byodStoreLocatorVisitors_programmatic_yoy_pct,
    adobe_byodInternalTmoVisitors_programmatic, adobe_byodInternalTmoVisitors_programmatic_wow, adobe_byodInternalTmoVisitors_programmatic_ly, CASE WHEN adobe_byodInternalTmoVisitors_programmatic_wow IS NULL OR adobe_byodInternalTmoVisitors_programmatic_wow = 0 THEN NULL ELSE ROUND((adobe_byodInternalTmoVisitors_programmatic - adobe_byodInternalTmoVisitors_programmatic_wow) / adobe_byodInternalTmoVisitors_programmatic_wow, 6) END AS adobe_byodInternalTmoVisitors_programmatic_wow_pct, CASE WHEN adobe_byodInternalTmoVisitors_programmatic_ly IS NULL OR adobe_byodInternalTmoVisitors_programmatic_ly = 0 THEN NULL ELSE ROUND((adobe_byodInternalTmoVisitors_programmatic - adobe_byodInternalTmoVisitors_programmatic_ly) / adobe_byodInternalTmoVisitors_programmatic_ly, 6) END AS adobe_byodInternalTmoVisitors_programmatic_yoy_pct,
    adobe_byodBouncersVisitors_programmatic,    adobe_byodBouncersVisitors_programmatic_wow,    adobe_byodBouncersVisitors_programmatic_ly,    CASE WHEN adobe_byodBouncersVisitors_programmatic_wow    IS NULL OR adobe_byodBouncersVisitors_programmatic_wow    = 0 THEN NULL ELSE ROUND((adobe_byodBouncersVisitors_programmatic    - adobe_byodBouncersVisitors_programmatic_wow)    / adobe_byodBouncersVisitors_programmatic_wow,    6) END AS adobe_byodBouncersVisitors_programmatic_wow_pct,    CASE WHEN adobe_byodBouncersVisitors_programmatic_ly    IS NULL OR adobe_byodBouncersVisitors_programmatic_ly    = 0 THEN NULL ELSE ROUND((adobe_byodBouncersVisitors_programmatic    - adobe_byodBouncersVisitors_programmatic_ly)    / adobe_byodBouncersVisitors_programmatic_ly,    6) END AS adobe_byodBouncersVisitors_programmatic_yoy_pct,
    adobe_byodOrders_programmatic,              adobe_byodOrders_programmatic_wow,              adobe_byodOrders_programmatic_ly,              CASE WHEN adobe_byodOrders_programmatic_wow              IS NULL OR adobe_byodOrders_programmatic_wow              = 0 THEN NULL ELSE ROUND((adobe_byodOrders_programmatic              - adobe_byodOrders_programmatic_wow)              / adobe_byodOrders_programmatic_wow,              6) END AS adobe_byodOrders_programmatic_wow_pct,              CASE WHEN adobe_byodOrders_programmatic_ly              IS NULL OR adobe_byodOrders_programmatic_ly              = 0 THEN NULL ELSE ROUND((adobe_byodOrders_programmatic              - adobe_byodOrders_programmatic_ly)              / adobe_byodOrders_programmatic_ly,              6) END AS adobe_byodOrders_programmatic_yoy_pct,
    -- OTHER
    adobe_byodVrChatVisitors_other,             adobe_byodVrChatVisitors_other_wow,             adobe_byodVrChatVisitors_other_ly,             CASE WHEN adobe_byodVrChatVisitors_other_wow             IS NULL OR adobe_byodVrChatVisitors_other_wow             = 0 THEN NULL ELSE ROUND((adobe_byodVrChatVisitors_other             - adobe_byodVrChatVisitors_other_wow)             / adobe_byodVrChatVisitors_other_wow,             6) END AS adobe_byodVrChatVisitors_other_wow_pct,             CASE WHEN adobe_byodVrChatVisitors_other_ly             IS NULL OR adobe_byodVrChatVisitors_other_ly             = 0 THEN NULL ELSE ROUND((adobe_byodVrChatVisitors_other             - adobe_byodVrChatVisitors_other_ly)             / adobe_byodVrChatVisitors_other_ly,             6) END AS adobe_byodVrChatVisitors_other_yoy_pct,
    adobe_byodCallVisitors_other,               adobe_byodCallVisitors_other_wow,               adobe_byodCallVisitors_other_ly,               CASE WHEN adobe_byodCallVisitors_other_wow               IS NULL OR adobe_byodCallVisitors_other_wow               = 0 THEN NULL ELSE ROUND((adobe_byodCallVisitors_other               - adobe_byodCallVisitors_other_wow)               / adobe_byodCallVisitors_other_wow,               6) END AS adobe_byodCallVisitors_other_wow_pct,               CASE WHEN adobe_byodCallVisitors_other_ly               IS NULL OR adobe_byodCallVisitors_other_ly               = 0 THEN NULL ELSE ROUND((adobe_byodCallVisitors_other               - adobe_byodCallVisitors_other_ly)               / adobe_byodCallVisitors_other_ly,               6) END AS adobe_byodCallVisitors_other_yoy_pct,
    adobe_byodStoreLocatorVisitors_other,       adobe_byodStoreLocatorVisitors_other_wow,       adobe_byodStoreLocatorVisitors_other_ly,       CASE WHEN adobe_byodStoreLocatorVisitors_other_wow       IS NULL OR adobe_byodStoreLocatorVisitors_other_wow       = 0 THEN NULL ELSE ROUND((adobe_byodStoreLocatorVisitors_other       - adobe_byodStoreLocatorVisitors_other_wow)       / adobe_byodStoreLocatorVisitors_other_wow,       6) END AS adobe_byodStoreLocatorVisitors_other_wow_pct,       CASE WHEN adobe_byodStoreLocatorVisitors_other_ly       IS NULL OR adobe_byodStoreLocatorVisitors_other_ly       = 0 THEN NULL ELSE ROUND((adobe_byodStoreLocatorVisitors_other       - adobe_byodStoreLocatorVisitors_other_ly)       / adobe_byodStoreLocatorVisitors_other_ly,       6) END AS adobe_byodStoreLocatorVisitors_other_yoy_pct,
    adobe_byodInternalTmoVisitors_other,        adobe_byodInternalTmoVisitors_other_wow,        adobe_byodInternalTmoVisitors_other_ly,        CASE WHEN adobe_byodInternalTmoVisitors_other_wow        IS NULL OR adobe_byodInternalTmoVisitors_other_wow        = 0 THEN NULL ELSE ROUND((adobe_byodInternalTmoVisitors_other        - adobe_byodInternalTmoVisitors_other_wow)        / adobe_byodInternalTmoVisitors_other_wow,        6) END AS adobe_byodInternalTmoVisitors_other_wow_pct,        CASE WHEN adobe_byodInternalTmoVisitors_other_ly        IS NULL OR adobe_byodInternalTmoVisitors_other_ly        = 0 THEN NULL ELSE ROUND((adobe_byodInternalTmoVisitors_other        - adobe_byodInternalTmoVisitors_other_ly)        / adobe_byodInternalTmoVisitors_other_ly,        6) END AS adobe_byodInternalTmoVisitors_other_yoy_pct,
    adobe_byodBouncersVisitors_other,           adobe_byodBouncersVisitors_other_wow,           adobe_byodBouncersVisitors_other_ly,           CASE WHEN adobe_byodBouncersVisitors_other_wow           IS NULL OR adobe_byodBouncersVisitors_other_wow           = 0 THEN NULL ELSE ROUND((adobe_byodBouncersVisitors_other           - adobe_byodBouncersVisitors_other_wow)           / adobe_byodBouncersVisitors_other_wow,           6) END AS adobe_byodBouncersVisitors_other_wow_pct,           CASE WHEN adobe_byodBouncersVisitors_other_ly           IS NULL OR adobe_byodBouncersVisitors_other_ly           = 0 THEN NULL ELSE ROUND((adobe_byodBouncersVisitors_other           - adobe_byodBouncersVisitors_other_ly)           / adobe_byodBouncersVisitors_other_ly,           6) END AS adobe_byodBouncersVisitors_other_yoy_pct,
    adobe_byodOrders_other,                     adobe_byodOrders_other_wow,                     adobe_byodOrders_other_ly,                     CASE WHEN adobe_byodOrders_other_wow                     IS NULL OR adobe_byodOrders_other_wow                     = 0 THEN NULL ELSE ROUND((adobe_byodOrders_other                     - adobe_byodOrders_other_wow)                     / adobe_byodOrders_other_wow,                     6) END AS adobe_byodOrders_other_wow_pct,                     CASE WHEN adobe_byodOrders_other_ly                     IS NULL OR adobe_byodOrders_other_ly                     = 0 THEN NULL ELSE ROUND((adobe_byodOrders_other                     - adobe_byodOrders_other_ly)                     / adobe_byodOrders_other_ly,                     6) END AS adobe_byodOrders_other_yoy_pct
  FROM with_comparisons
),

-- -----------------------------------------------------------------------
-- STEP 6: max_data_date
-- -----------------------------------------------------------------------
with_max_date AS (
  SELECT
    *,
    MAX(CASE WHEN adobe_byodVrChatVisitors_allChannels IS NOT NULL THEN week_sun_to_sat END) OVER () AS max_data_date
  FROM with_pcts
)

-- -----------------------------------------------------------------------
-- FINAL OUTPUT — wide table, one row per week
-- -----------------------------------------------------------------------
SELECT
  week_sun_to_sat,
  'ADOBE_BYOD_OUTCOMES'  AS data_source,
  max_data_date,
  -- ALL CHANNELS
  adobe_byodVrChatVisitors_allChannels,      adobe_byodVrChatVisitors_allChannels_wow,      adobe_byodVrChatVisitors_allChannels_ly,      adobe_byodVrChatVisitors_allChannels_wow_pct,      adobe_byodVrChatVisitors_allChannels_yoy_pct,
